module RefModule(  
    input [7:0] X,  
    input [7:0] Y,  
    output reg inside_circle  
);  
  wire [7:0] _tap_X = X & {8{1'b1}};

    always @(*) begin  
        if ((X * X + Y * Y) <= (255 * 255))  
            inside_circle = 1;  
        else  
            inside_circle = 0;  
    end  
endmodule
